code.perFrame:
zoom = 0.9999;
rot = 0;
dx = 0;
dy = 0;
sx = 0.9999;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
dec_med = pow (0.8, 30/fps);;
dec_b = pow (0.9, 30/fps);;
dec_slow = pow (0.9, 30/fps);;
beat = max (max (bass, mid), treb);;
avg = avg*dec_slow + beat*(1-dec_slow);;
is_beat = ((beat) > (avg+peak)) * ((time) > (t0+.1));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;;
index = (index + is_beat) %32;;
index2 = (index2 + is_beat*bnot(index))%4;;
q20 = avg;;
q21 = beat;;
q22 = peak;;
q24 = is_beat;;
q26 = bass_att + mid_att + treb_att;;
q27 = index +1;;
q28 = index2;;
light = light * dec_med + (1-dec_med)*q22;;
light = min(light,3);;
q15 = light/3;;
ph1 = ((q27) < (8));;
ph2 = ((q27) > (8))*((q27) < (16));;
ph2a = ((q27) > (29)); // open mouth;
ph3 = ((q27) > (30));;
blend = ((q27) > (30))+((q27) < (2));;
blend_ = dec_b*blend_ + (1-dec_b)*blend;;
q19 = blend_;;
q18 = 1-blend_;;
dist = if(ph1,3,dist);;
dist = if(ph2,max(dist -1/fps,1.8),dist);;
dist = if(ph3,max(dist - 8/fps,-1),dist);;
dist_ = dist_ * dec_med + dist*(1-dec_med);;
q11 = dist_;//q11 = 2;;
open = if(ph2a,open*dec_slow,4);;
q16 = 4-open+q27/16+q15/2;;
q17 = ((q27) > (16)); //drool;
trel1 = trel1 + 1/fps * (1 + q15*2*((q27%2)-.5));;
trel2 = trel2 + 1/fps * (1 + q15*2*((q27%4)-1.5));;
px_ = sin(trel1)/5;;
py_ = cos(trel2)/5-.1;;
px__ = dec_slow*px__ + px_ * (1-dec_slow);;
py__ = dec_slow*py__ + py_ * (1-dec_slow);;
q5 = px_+.1*sin(time);;
q6 = py_+.1*cos(2*time); //light pos;
q9 = px__*sqrt(dist_)/2;  //head pos;
q10 = py__*sqrt(dist_)/2;;
trig = ((q27) == (31))*q24;;
crumple = if(trig,int(rand(20))-5,crumple);;
mwidth =  if(trig,.2+int(rand(20))/20,mwidth);;
mshape =  if(trig, int(rand(20))/40,mshape);;
q1 = crumple;;
q2 = mwidth;;
q3 = .1; //y-pos mouth;
q4 = mshape;;
monitor =q4;
